import{_ as s,o as a,c as l,V as n}from"./chunks/framework.5a3bb230.js";const d=JSON.parse('{"title":"Rust入门（一）：第一个程序","description":"","frontmatter":{"title":"Rust入门（一）：第一个程序"},"headers":[],"relativePath":"web/小程序/01.基础入门.md","filePath":"web/小程序/01.基础入门.md"}'),o={name:"web/小程序/01.基础入门.md"},e=n(`<h1 id="rust入门-一-第一个程序" tabindex="-1">Rust入门（一）：第一个程序 <a class="header-anchor" href="#rust入门-一-第一个程序" aria-label="Permalink to &quot;Rust入门（一）：第一个程序&quot;">​</a></h1><h2 id="rust是什么" tabindex="-1">Rust是什么 <a class="header-anchor" href="#rust是什么" aria-label="Permalink to &quot;Rust是什么&quot;">​</a></h2><p>Rust是一门专注于安全的系统编程语言，支持函数式和命令式以及泛型等编程范式。 Rust最初是由<a href="https://baike.baidu.com/item/Mozilla/7148071?fromModule=lemma_inlink" target="_blank" rel="noreferrer">Mozilla</a>研究院的Graydon Hoare设计创造，然后在Dave Herman, Brendan Eich以及很多其他人的贡献下逐步完善的，设计者设计的初衷是想要在保证性能的同时提供更好的内存安全。</p><p>Rust编译器是在<a href="https://baike.baidu.com/item/MIT/31539?fromModule=lemma_inlink" target="_blank" rel="noreferrer">MIT</a> License 和 <a href="https://baike.baidu.com/item/Apache/6265?fromModule=lemma_inlink" target="_blank" rel="noreferrer">Apache</a> License 2.0双重协议声明下的免费开源软件。 Rust已经连续七年（2016，2017，2018，2019，2020, 2021, 2022）在Stack Overflow开发者调查的“最受喜爱编程语言”评选项目中折取桂冠。</p><h2 id="rust的特点" tabindex="-1">Rust的特点 <a class="header-anchor" href="#rust的特点" aria-label="Permalink to &quot;Rust的特点&quot;">​</a></h2><p>安全、可靠、高效</p><h2 id="rust的使用场景" tabindex="-1">Rust的使用场景 <a class="header-anchor" href="#rust的使用场景" aria-label="Permalink to &quot;Rust的使用场景&quot;">​</a></h2><ul><li>编写系统层面代码</li><li>命令行工具</li><li>网络服务</li><li>WEB应用</li></ul><h2 id="rust安装" tabindex="-1">Rust安装 <a class="header-anchor" href="#rust安装" aria-label="Permalink to &quot;Rust安装&quot;">​</a></h2><p>rust的安装是通过 <code>rustup</code>完成的，只需要在官网下载rustup，就会自动安装配置好系统变量</p><p>在 Windows 上，前往 <a href="https://www.rust-lang.org/tools/install" target="_blank" rel="noreferrer">https://www.rust-lang.org/install.html</a> 并按照说明安装 Rust</p><p>运行rust还需要安装 <a href="https://visualstudio.microsoft.com/downloads/" target="_blank" rel="noreferrer">Visual Studio 2022</a>环境，并且安装以下模块</p><ul><li>“使用 C++ 的桌面开发”，</li><li>Windows 10 （或 11） SDK，</li><li>英语语言包，以及其他你所需要的语言包。</li></ul><p>之后如果使用VScode作为开发ide，安装以下插件：</p><ul><li>rust-analyzer : 它会实时编译和分析你的 Rust 代码，提示代码中的错误，并对类型进行标注。</li><li>Better Toml : 使用 toml 做项目的配置管理。</li><li>rust syntax：为代码提供语法高亮。</li></ul><h2 id="hello-world" tabindex="-1">Hello World <a class="header-anchor" href="#hello-world" aria-label="Permalink to &quot;Hello World&quot;">​</a></h2><p>rust程序代码文件的后缀名是.rs，新建一个.rs 文件开始编写程序：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#F78C6C;">fn</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">main</span><span style="color:#89DDFF;">()</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#82AAFF;">println!</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Hello, world!</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p><code>fn main() </code> 作为程序的主函数存在，它总是最先运行的代码，也没有返回值，<code>println!</code> 则是一个Rust 宏，这个在后续会提到，在windows 命令行中，使用如下命令编译刚刚写出的程序：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> rustc main</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">rs</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">\\main</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">exe</span></span>
<span class="line"><span style="color:#FFCB6B;">Hello</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">world!</span></span></code></pre></div><p>此时rust会将刚刚编写代码编译成一个可执行文件main.exe，以及当使用 CMD 时会有一个包含调试信息、扩展名为 <em>.pdb</em> 的文件</p><h2 id="使用cargo" tabindex="-1">使用Cargo <a class="header-anchor" href="#使用cargo" aria-label="Permalink to &quot;使用Cargo&quot;">​</a></h2><p>rust推荐使用 Cargo 来管理他们的 Rust 项目，类似java里面的maven和node里的npm，它通过编写配置文件来导入对应的包，同时也具有lock这样的机制，在命令行写入以下命令来创建一个rust项目：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">cargo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">hello_cargo</span></span></code></pre></div><p>创建后生存了一个 <em>Cargo.toml</em> 文件和 <em>src</em> 目录，其中包含一个 <em>main.rs</em> 文件，toml文件就是cargo的配置文件，其默认内容如下：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">package</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#项目的配置信息</span></span>
<span class="line"><span style="color:#A6ACCD;">name </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">hello_cargo</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">   </span><span style="color:#676E95;font-style:italic;">#项目的名称</span></span>
<span class="line"><span style="color:#A6ACCD;">version </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">0.1.0</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">      </span><span style="color:#676E95;font-style:italic;">#项目的版本</span></span>
<span class="line"><span style="color:#A6ACCD;">edition </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">2021</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">       </span><span style="color:#676E95;font-style:italic;">#Rust 版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># See more keys and their definitions at https://doc.rust-lang.org/cargo/reference/manifest.html</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">dependencies</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#依赖</span></span></code></pre></div><p>我们可以使用如下几种的方式来导入一个包</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">dependencies</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#A6ACCD;">rand </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">0.3.14</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">   </span><span style="color:#676E95;font-style:italic;">#从crates.io导入0.3.14版本的rand包</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">rand </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> git </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">https://github.com/rust-lang-nursery/rand</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">#从git导入</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">bar </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> path </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">../bar</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">#本地导入</span></span></code></pre></div><h2 id="rust的运行" tabindex="-1">Rust的运行 <a class="header-anchor" href="#rust的运行" aria-label="Permalink to &quot;Rust的运行&quot;">​</a></h2><p>每次初始化和新增依赖后，我们需要构建我们的项目，使用如下的命令</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">cargo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">build</span></span></code></pre></div><p>构建后，将会新增target文件夹和根 <em>.lock</em> 文件，在 target\\debug\\hello_cargo.exe 生成了我们需要的可执行文件，而 .lcok 文件里面记录了每个库使用的精确的版本。之后构建的时候会直接读取该文件并使用里面的版本。 Cargo只有在你希望它更新的时候才会更新新版本，手动修改Cargo.toml里的版本成新的版本号或者运行cargo update。</p><p>使用如下的命令可以同时编译并运行生成的可执行文件，在开发中一般使用这个：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">cargo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">run</span></span></code></pre></div><p>使用如下命令可以检查代码是不是存在语法错误：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">cargo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">check</span></span></code></pre></div><p>当你需要最终编译发布你的程序时，使用如下命令优化编译：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">cargo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">build</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--release</span></span></code></pre></div>`,38),t=[e];function p(r,c,i,y,D,u){return a(),l("div",null,t)}const F=s(o,[["render",p]]);export{d as __pageData,F as default};
